import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] arr = new long[N];
            for (int i = 0; i < N; i++) arr[i] = fs.nextLong();
            HashMap<Long, Long> freq = new HashMap<>(N * 2);
            for (long v : arr) freq.put(v, freq.getOrDefault(v, 0L) + 1);
            long total = 1L * N * (N - 1) / 2;
            long same = 0;
            for (long c : freq.values()) same += c * (c - 1) / 2;
            sb.append(total - same).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
    }
}

